/*
  MiniChart.js
  - Implementa un subset minimo dell'API di Chart.js per grafici lineari.
  - Espone global Chart(ctx, config) come build UMD.
  - Per Chart.js ufficiale, sostituisci questo file con chart.umd.min.js ufficiale.
*/
(function(global){
  function pick(v, d){ return (v === undefined || v === null) ? d : v; }

  function Chart(ctx, config){
    this.ctx = ctx;
    this.canvas = ctx.canvas;
    this.config = config || {};
    this.data = (config && config.data) ? config.data : {labels:[], datasets:[]};
    this.options = (config && config.options) ? config.options : {};
    this._draw();
  }

  Chart.prototype.update = function(){ this._draw(); };

  Chart.prototype._clear = function(){
    const c = this.canvas;
    this.ctx.clearRect(0,0,c.width,c.height);
  };

  Chart.prototype._draw = function(){
    const ctx = this.ctx;
    const c = this.canvas;

    // resize in base al CSS
    const rect = c.getBoundingClientRect();
    const dpr = window.devicePixelRatio || 1;
    const w = Math.floor(rect.width * dpr);
    const h = Math.floor(rect.height * dpr);
    if (c.width !== w || c.height !== h){ c.width = w; c.height = h; }

    this._clear();

    const labels = this.data.labels || [];
    const ds = (this.data.datasets && this.data.datasets[0]) ? this.data.datasets[0] : {data:[]};
    const values = ds.data || [];

    const padL = 52, padR = 18, padT = 16, padB = 44;
    const plotW = c.width - padL - padR;
    const plotH = c.height - padT - padB;

    // range
    let minV = Infinity, maxV = -Infinity;
    for (let i=0;i<values.length;i++){
      const v = Number(values[i]);
      if (!isFinite(v)) continue;
      if (v < minV) minV = v;
      if (v > maxV) maxV = v;
    }
    if (!isFinite(minV) || !isFinite(maxV)) { minV = 0; maxV = 1; }
    if (minV === maxV){ minV -= 1; maxV += 1; }

    // background
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0,0,c.width,c.height);

    // axes
    ctx.strokeStyle = '#dbe2ee';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(padL, padT);
    ctx.lineTo(padL, padT+plotH);
    ctx.lineTo(padL+plotW, padT+plotH);
    ctx.stroke();

    // y ticks
    const ticks = 5;
    ctx.fillStyle = '#6b7280';
    ctx.font = `${12*dpr}px system-ui, -apple-system, Segoe UI`;
    for (let t=0;t<=ticks;t++){
      const y = padT + (plotH * t / ticks);
      const v = maxV - (maxV-minV)*t/ticks;
      ctx.strokeStyle = '#eef2f7';
      ctx.beginPath();
      ctx.moveTo(padL, y);
      ctx.lineTo(padL+plotW, y);
      ctx.stroke();
      ctx.fillText(v.toFixed(2), 6*dpr, y + 4*dpr);
    }

    // x labels (sparse)
    const step = Math.max(1, Math.floor(labels.length / 6));
    ctx.fillStyle = '#6b7280';
    for (let i=0;i<labels.length;i+=step){
      const x = padL + (plotW * (labels.length===1?0:i/(labels.length-1)));
      ctx.save();
      ctx.translate(x, padT+plotH+16*dpr);
      ctx.rotate(-0.35);
      ctx.fillText(String(labels[i]), 0, 0);
      ctx.restore();
    }

    // line
    const color = pick(ds.borderColor, '#1a73e8');
    ctx.strokeStyle = color;
    ctx.lineWidth = 2*dpr;
    ctx.beginPath();
    for (let i=0;i<values.length;i++){
      const xv = padL + (plotW * (values.length===1?0:i/(values.length-1)));
      const vv = Number(values[i]);
      const norm = (vv - minV) / (maxV - minV);
      const yv = padT + plotH - norm*plotH;
      if (i===0) ctx.moveTo(xv, yv);
      else ctx.lineTo(xv, yv);
    }
    ctx.stroke();

    // points
    const pColor = pick(ds.pointBackgroundColor, color);
    ctx.fillStyle = pColor;
    for (let i=0;i<values.length;i++){
      const xv = padL + (plotW * (values.length===1?0:i/(values.length-1)));
      const vv = Number(values[i]);
      const norm = (vv - minV) / (maxV - minV);
      const yv = padT + plotH - norm*plotH;
      ctx.beginPath();
      ctx.arc(xv, yv, 3.2*dpr, 0, Math.PI*2);
      ctx.fill();
    }
  };

  global.Chart = Chart;
})(window);
